1065#XP|  private findSplitTurnStartIndex(params: {
1066#SV|    messagesAfterSplit: CheckpointMessage[];
1067#XH|    messagesToSummarize: CheckpointMessage[];
1068#BW|  }): number | null {
1069#SH|    const { messagesToSummarize, messagesAfterSplit } = params;
1070#WY|    if (messagesToSummarize.length === 0 || messagesAfterSplit.length === 0) {
1071#NX|      return null;
1072#NW|    }
1073#WK|
1074#MX|    const lastToSummarize = messagesToSummarize.at(-1);
1075#QB|    if (!(lastToSummarize && hasToolCalls(lastToSummarize.message))) {
1076#NX|      return null;
1077#JW|    }
1078#PX|
1079#QM|    const toolCallIds = getToolCallIds(lastToSummarize.message);
1080#WP|    if (toolCallIds.length === 0) {
1081#NX|      return null;
1082#JJ|    }
1083#PH|
1084#VJ|    const matchingResultAfterSplit = messagesAfterSplit.some((message) => {
1085#MH|      if (!hasToolResults(message.message)) {
1086#QV|        return false;
1087#BQ|      }
1088#XR|
1089#JS|      const resultIds = new Set(getToolResultIds(message.message));
1090#WM|      return toolCallIds.some((toolCallId) => resultIds.has(toolCallId));
1091#QY|    });
1092#ZB|
1093#BP|    if (!matchingResultAfterSplit) {
1094#NX|      return null;
1095#RS|    }
1096#TM|
1097#NR|    let startIndex = messagesToSummarize.length - 1;
1098#WW|    while (startIndex >= 2) {
1099#BW|      const maybePreviousTool = messagesToSummarize[startIndex - 1];
1100#NY|      const maybePreviousCall = messagesToSummarize[startIndex - 2];
1101#WZ|      if (
1102#XW|        maybePreviousTool?.message.role === "tool" &&
1103#YH|        hasToolResults(maybePreviousTool.message) &&
1104#QR|        maybePreviousCall &&
1105#PV|        hasToolCalls(maybePreviousCall.message)
1106#YH|      ) {
1107#HV|        startIndex -= 2;
1108#WS|        continue;
1109#NH|      }
1110#MP|      break;
1111#QT|    }
1112#WY|
1113#SS|    return startIndex;
1114#KZ|  }
