215#WX|      };
216#WZ|    };
217#WZ|
218#RJ|    const firstEntry = this.entries[0];
219#RY|    if (firstEntry || rightTextStyled) {
220#BX|      const maxLeftWidth = rightTextPlain
221#PB|        ? Math.max(0, contentWidth - visibleWidth(rightTextPlain) - 1)
222#XT|        : contentWidth;
223#ZS|      const left = firstEntry
224#VS|        ? renderLeftEntry(firstEntry, maxLeftWidth)
225#JM|        : null;
226#KZ|      const leftWidth = left ? visibleWidth(left.plain) : 0;
227#MK|      const gap = rightTextPlain
228#BY|        ? Math.max(1, contentWidth - leftWidth - visibleWidth(rightTextPlain))
229#TT|        : 0;
230#KT|      const line = `${" ".repeat(1)}${left?.styled ?? ""}${" ".repeat(gap)}${rightTextStyled}`;
231#QQ|      lines.push(line + " ".repeat(Math.max(0, width - visibleWidth(line))));
232#PJ|    }
233#ZQ|
234#QH|    for (const entry of this.entries.slice(1)) {
235#PK|      const left = renderLeftEntry(entry, contentWidth);
236#YM|      const line = `${" ".repeat(1)}${left.styled}`;
237#QQ|      lines.push(line + " ".repeat(Math.max(0, width - visibleWidth(line))));
238#MN|    }
239#QN|
240#PV|    return lines;
241#HX|  }
242#HH|
243#JN|  private start(): void {
244#SQ|    this.intervalId = setInterval(() => {
245#HW|      this.currentFrame = (this.currentFrame + 1) % this.frames.length;
246#JB|      this.invalidate();
247#PP|      this.tui.requestRender();
248#KB|    }, 80);
249#HY|  }
